CREATE TABLE public.admin_emails (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), email text UNIQUE NOT NULL, created_at timestamp with time zone NOT NULL DEFAULT now()); ALTER TABLE public.admin_emails ENABLE ROW LEVEL SECURITY; CREATE POLICY "Anyone can check admin emails" ON public.admin_emails FOR SELECT TO authenticated USING (true); CREATE OR REPLACE FUNCTION public.is_admin_email(_email text) RETURNS boolean LANGUAGE sql STABLE SECURITY DEFINER SET search_path = public AS $$ SELECT EXISTS (SELECT 1 FROM public.admin_emails WHERE email = lower(_email)) $$;